const query = dv.search_query || "recent emails";

try {
  const res = await fetch("https://empowerai365.app.n8n.cloud/webhook/872acbb4-38cf-4ba1-add4-0daa5a06018c", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      chatInput: "Search my Gmail for: " + query
    })
  });

  const data = await res.json();
  const output = data.output || data.text || data.message || "No results found.";
  return { result: output };

} catch (err) {
  return { result: "Connection error while searching Gmail. Please try again." };
}

